mapper.insert:
/* AdminMenuMapper.insertMenu */
INSERT INTO TB_MENU (
	 MENU_PID
	,MENU_NM
	,MENU_ORDR
	,MENU_TYPE
	,MENU_DEPTH
	,MENU_URL
	,MENU_ICON
	,USE_YN
	,SITE_CODE
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{menuPid}
	,#{menuNm}
	,#{menuOrdr}
	,#{menuType}
	,#{menuDepth}
	,#{menuUrl}
	,#{menuIcon}
	,#{useYn}
	,#{siteCode}
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* AdminMenuMapper.updateMenu */
UPDATE
	TB_MENU
SET
	 MENU_NM = #{menuNm}
	,MENU_ORDR = #{menuOrdr}
	,MENU_TYPE = #{menuType}
	,MENU_URL = #{menuUrl}
	,MENU_ICON = #{menuIcon}
	,USE_YN = #{useYn}
	,UPD_ID = #{userId}
	,UPD_DT = now()
WHERE
	MENU_ID = #{menuId}
AND
	MENU_PID = #{menuPid}
AND
	SITE_CODE = #{siteCode}

mapper.delete:
/* AdminMenuMapper.deleteMenu */
DELETE FROM TB_MENU
WHERE
	MENU_ID = #{menuId}
AND
	MENU_PID = #{menuPid}
AND
	SITE_CODE = #{siteCode}

